#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[2005]; scanf("%s", s);
        int moves = 0;
        int len = N;
        while (len > 0) {
            if (len % 2 == 0) {
                int half = len / 2;
                if (strncmp(s, s + half, half) == 0) {
                    // duplicate operation reversed
                    s[half] = '\0';
                    len = half;
                    moves++;
                    continue;
                }
            }
            // remove last character
            s[--len] = '\0';
            moves++;
        }
        printf("%d\n", moves);
    }
    return 0;
}

