import sys

def min_moves(s: str) -> int:
    moves = 0
    while s:
        n = len(s)
        if n % 2 == 0 and s[:n//2] == s[n//2:]:
            s = s[:n//2]
        else:
            s = s[:-1]
        moves += 1
    return moves

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        out_lines.append(str(min_moves(s)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

